'use client'

import { useCallback, type ReactNode } from 'react'
import Image from 'next/image'
import { motion } from 'framer-motion'
import ThemeToggle from '@/components/ThemeToggle'

interface BioLink {
  id: string
  label: string
  url: string
  icon: ReactNode
}

interface BioLinkButtonProps {
  link: BioLink
  index: number
  baseDelay: number
  onClick: (link: BioLink) => void
}

function BioLinkButton({ link, index, baseDelay, onClick }: BioLinkButtonProps) {
  return (
    <motion.button
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: baseDelay + index * 0.05 }}
      onClick={() => onClick(link)}
      className="w-full flex items-center gap-3 px-4 py-3 rounded-xl border cursor-pointer
        bg-[var(--bg-secondary)] border-[var(--border-color)] text-[var(--text-primary)]
        transition-all duration-200 hover:scale-[1.02] active:scale-[0.98]
        hover:border-[var(--accent-color)] hover:bg-[var(--bg-tertiary)]"
    >
      <span className="text-[var(--accent-color)]">{link.icon}</span>
      <span className="text-sm font-medium">{link.label}</span>
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className="w-4 h-4 ml-auto text-[var(--text-muted)]">
        <path d="M18 13v6a2 2 0 01-2 2H5a2 2 0 01-2-2V8a2 2 0 012-2h6M15 3h6v6M10 14L21 3"/>
      </svg>
    </motion.button>
  )
}

